// All values in millimeters
export const WALL_THICKNESS = 150;
export const WALL_HEIGHT = 3000;
export const DOOR_WIDTH = 900;
export const DOOR_HEIGHT = 2100;
export const DOOR_SILL_HEIGHT = 0;
export const WINDOW_WIDTH = 1200;
export const WINDOW_HEIGHT = 1200;
export const WINDOW_SILL_HEIGHT = 900;

export const SNAP_DISTANCE_PX = 10;
export const MIN_WALL_LENGTH = 100;

export const DEFAULT_ZOOM = 0.1;
export const MIN_ZOOM = 0.02;
export const MAX_ZOOM = 2.0;
export const ZOOM_FACTOR = 1.1;

export const GRID_MINOR = 50;    // mm
export const GRID_MAJOR = 1000;  // mm

export const PREVIEW_LABEL_OFFSET = 150;
export const DIMENSION_DEFAULT_OFFSET = 300;

export const COLUMN_WIDTH = 300;  // mm
export const COLUMN_DEPTH = 300;  // mm
export const BEAM_WIDTH = 250;    // mm
export const BEAM_DEPTH = 450;    // mm
export const STAIR_WIDTH = 1000;  // mm
export const STAIR_RISERS = 18;
export const STAIR_RISER_HEIGHT = 175; // mm
export const STAIR_TREAD_DEPTH = 280;  // mm
export const SLAB_THICKNESS = 200; // mm
export const SLAB_ELEVATION = 0;   // mm
export const SECTION_DEPTH = 2000; // mm

export const LANDING_WIDTH = 1000;  // mm
export const LANDING_DEPTH = 1000;  // mm
export const LANDING_THICKNESS = 200; // mm

export const FIXTURE_KITCHEN_TOP_WIDTH = 2400;
export const FIXTURE_KITCHEN_TOP_DEPTH = 600;
export const FIXTURE_TOILET_WIDTH = 700;
export const FIXTURE_TOILET_DEPTH = 400;
export const FIXTURE_LAVATORY_WIDTH = 500;
export const FIXTURE_LAVATORY_DEPTH = 400;
export const FIXTURE_TABLE_WIDTH = 1200;
export const FIXTURE_TABLE_DEPTH = 800;
export const FIXTURE_TV_WIDTH = 1200;
export const FIXTURE_TV_DEPTH = 100;
export const FIXTURE_SOFA_WIDTH = 2000;
export const FIXTURE_SOFA_DEPTH = 900;

export const ROOM_COLOR = '#E8F0FE';

export const ENDPOINT_MERGE_TOLERANCE = 1; // mm
export const MIN_ROOM_AREA = 100000; // mm² (0.1 m²)

import {
  FIXTURE_KITCHEN_TOP_WIDTH, FIXTURE_KITCHEN_TOP_DEPTH,
  FIXTURE_TOILET_WIDTH, FIXTURE_TOILET_DEPTH,
  FIXTURE_LAVATORY_WIDTH, FIXTURE_LAVATORY_DEPTH,
  FIXTURE_TABLE_WIDTH, FIXTURE_TABLE_DEPTH,
  FIXTURE_TV_WIDTH, FIXTURE_TV_DEPTH,
  FIXTURE_SOFA_WIDTH, FIXTURE_SOFA_DEPTH,
} from '@/domain/defaults';

export const TOOLS = {
  SELECT: 'select',
  DIMENSION: 'dimension',
  WALL: 'wall',
  BEAM: 'beam',
  STAIR: 'stair',
  SECTION: 'section',
  SLAB: 'slab',
  ROOM: 'room',
  DOOR: 'door',
  WINDOW: 'window',
  COLUMN: 'column',
  LANDING: 'landing',
  FIXTURE: 'fixture',
};

export const FIXTURE_TYPES = {
  KITCHEN_TOP: 'kitchenTop',
  TOILET: 'toilet',
  LAVATORY: 'lavatory',
  TABLE: 'table',
  TV: 'tv',
  SOFA: 'sofa',
};

export const FIXTURE_DEFAULTS = {
  [FIXTURE_TYPES.KITCHEN_TOP]: { width: FIXTURE_KITCHEN_TOP_WIDTH, depth: FIXTURE_KITCHEN_TOP_DEPTH },
  [FIXTURE_TYPES.TOILET]: { width: FIXTURE_TOILET_WIDTH, depth: FIXTURE_TOILET_DEPTH },
  [FIXTURE_TYPES.LAVATORY]: { width: FIXTURE_LAVATORY_WIDTH, depth: FIXTURE_LAVATORY_DEPTH },
  [FIXTURE_TYPES.TABLE]: { width: FIXTURE_TABLE_WIDTH, depth: FIXTURE_TABLE_DEPTH },
  [FIXTURE_TYPES.TV]: { width: FIXTURE_TV_WIDTH, depth: FIXTURE_TV_DEPTH },
  [FIXTURE_TYPES.SOFA]: { width: FIXTURE_SOFA_WIDTH, depth: FIXTURE_SOFA_DEPTH },
};

