383→const FIXTURE_BUILDERS = {
384→  kitchenTop: buildKitchenTopFixture,
385→  toilet: buildToiletFixture,
386→  lavatory: buildLavatoryFixture,
387→  table: buildTableFixture,
388→  tv: buildTvFixture,
389→  sofa: buildSofaFixture,
390→};
