256→function createOpeningInsertDescriptor(opening) {
257→  return createBoxDescriptor(
258→    opening.id,
259→    opening.kind,
260→    opening.centerPoint,
261→    {
262→      x: opening.visibleWidth,
263→      y: opening.visibleHeight,
264→      z: getInsertThickness(opening.kind, opening.wallThickness),
265→    },
266→    opening.visibleBaseElevation,
267→    opening.angle,
268→    {
269→      sourceId: opening.sourceId,
270→      floorId: opening.metadata.floorId,
271→      wallId: opening.wallId,
272→      openingKind: opening.kind,
273→    }
274→  );
275→}
