322→function buildFixtureObjects(floor, floorLevel) {
323→  return (floor.fixtures || []).map((fixture) => {
324→    const descriptor = createBoxDescriptor(
325→      fixture.id,
326→      'fixture',
327→      { x: fixture.x, y: fixture.y },
328→      {
329→        x: fixture.width,
330→        y: FIXTURE_3D_HEIGHTS[fixture.fixtureType] || 750,
331→        z: fixture.depth,
332→      },
333→      floorLevel,
334→      (fixture.rotation || 0) * Math.PI / 180,
335→      {
336→        sourceId: fixture.id,
337→        floorId: floor.id,
338→        materialKey: 'fixture_' + fixture.fixtureType,
339→      }
340→    );
341→    descriptor.geometry = 'fixture';
342→    descriptor.fixtureType = fixture.fixtureType;
343→    return descriptor;
344→  });
