148→export function getFloorLevelIndex(floor, fallbackIndex = 0) {
149→  if (!floor) return fallbackIndex;
150→  if (Number.isFinite(floor.levelIndex)) return floor.levelIndex;
151→  if (Number.isFinite(floor.level)) return floor.level;
152→  return fallbackIndex;
